## Files
- src/app/api/xrpc/[...method]/route.ts (create)

## What to do
Create a catch-all API route that proxies XRPC calls from the client to the AT Protocol server using the server-side Agent.

This single route handles ALL XRPC methods the app uses. The client will call `/api/xrpc/com.atproto.repo.getRecord?repo=...&collection=...` etc.

### GET handler
For read operations. Extracts the method from the URL path, reads query params, and forwards to the Agent.

```typescript
import { NextRequest, NextResponse } from "next/server"
import { Agent } from "@atproto/api"
import { getOAuthClient } from "@/lib/auth/oauth-client"
import { getSessionDid } from "@/lib/auth/session"

export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ method: string[] }> }
) {
  const { method } = await params
  const methodName = method.join(".")  // e.g. ["com", "atproto", "repo", "getRecord"] → "com.atproto.repo.getRecord"

  const did = await getSessionDid()
  if (!did) return NextResponse.json({ error: "Not authenticated" }, { status: 401 })

  const client = await getOAuthClient()
  const oauthSession = await client.restore(did)
  const agent = new Agent(oauthSession)

  // Parse query params into an object
  const queryParams = Object.fromEntries(request.nextUrl.searchParams.entries())

  // Call the XRPC method dynamically
  // Use agent.call(methodName, queryParams) for queries
  const response = await (agent as any).call(methodName, { params: queryParams })
  // Actually, use the lower-level: agent.api.xrpc.call(methodName, queryParams)
  // The exact API: const result = await oauthSession.fetchHandler(methodName, { method: "GET", ... })
  // Simplest approach: use agent.com.atproto.repo.getRecord etc based on methodName

  // Better approach — use a switch/map for the known methods:
  switch (methodName) {
    case "com.atproto.repo.getRecord": {
      const result = await agent.com.atproto.repo.getRecord(queryParams as any)
      return NextResponse.json(result.data)
    }
    case "com.atproto.repo.listRecords": {
      const result = await agent.com.atproto.repo.listRecords(queryParams as any)
      return NextResponse.json(result.data)
    }
    case "com.atproto.server.getSession": {
      const result = await agent.com.atproto.server.getSession()
      return NextResponse.json(result.data)
    }
    case "com.atproto.sync.getBlob": {
      // Special: return the raw blob data with correct content-type
      const result = await agent.com.atproto.sync.getBlob(queryParams as any)
      return new NextResponse(result.data, {
        headers: { "Content-Type": result.headers["content-type"] || "application/octet-stream" }
      })
    }
    default:
      return NextResponse.json({ error: `Unknown method: ${methodName}` }, { status: 400 })
  }
}
```

### POST handler
For write operations.

```typescript
export async function POST(
  request: NextRequest,
  { params }: { params: Promise<{ method: string[] }> }
) {
  const { method } = await params
  const methodName = method.join(".")

  const did = await getSessionDid()
  if (!did) return NextResponse.json({ error: "Not authenticated" }, { status: 401 })

  const client = await getOAuthClient()
  const oauthSession = await client.restore(did)
  const agent = new Agent(oauthSession)

  switch (methodName) {
    case "com.atproto.repo.putRecord": {
      const body = await request.json()
      const result = await agent.com.atproto.repo.putRecord(body)
      return NextResponse.json(result.data)
    }
    case "com.atproto.repo.deleteRecord": {
      const body = await request.json()
      const result = await agent.com.atproto.repo.deleteRecord(body)
      return NextResponse.json(result.data)
    }
    case "com.atproto.repo.uploadBlob": {
      const contentType = request.headers.get("content-type") || "application/octet-stream"
      const buffer = await request.arrayBuffer()
      const result = await agent.com.atproto.repo.uploadBlob(new Uint8Array(buffer), { encoding: contentType })
      return NextResponse.json(result.data)
    }
    case "com.atproto.identity.updateHandle": {
      const body = await request.json()
      const result = await agent.com.atproto.identity.updateHandle(body)
      return NextResponse.json(result.data)
    }
    case "com.atproto.server.requestPasswordReset": {
      const body = await request.json()
      const result = await agent.com.atproto.server.requestPasswordReset(body)
      return NextResponse.json(result.data)
    }
    case "com.atproto.server.resetPassword": {
      const body = await request.json()
      const result = await agent.com.atproto.server.resetPassword(body)
      return NextResponse.json(result.data)
    }
    default:
      return NextResponse.json({ error: `Unknown method: ${methodName}` }, { status: 400 })
  }
}
```

Error handling: Wrap each case in try/catch. On error, extract status from the error object if available, otherwise 500. Return `{ error: message }`.

### Important: listRecords limit param
The `limit` query param comes as a string from URL params. Cast it to number: `{ ...queryParams, limit: queryParams.limit ? Number(queryParams.limit) : undefined }`.

## Do not
- Import from @atproto/oauth-client-browser
- Use "use client"
- Create separate route files for each method (use the catch-all pattern)
- Expose methods not listed above (security: only whitelist known methods)

